168	/// Partial-update descriptor for [`PackEditor::edit_macro`].
169	///
170	/// `None` for a field means "leave unchanged". `Some(None)` clears an optional field.
171	/// `Some(Some(v))` sets the field to `v`. The `keys` field replaces the entire vec when `Some`.
172	#[derive(Debug, Clone, Default)]
173	pub struct MacroUpdates {
174	    pub phrase: Option<Option<String>>,
175	    pub if_flag: Option<Option<String>>,
176	    pub set_flag: Option<Option<String>>,
177	    pub sound: Option<Option<PathBuf>>,
178	    pub keys: Option<Vec<KeyAction>>,
179	}
