1	/// Pack editor panel for browsing and editing macro packs.
2	///
3	/// All egui code is gated to `gui` — the default build (no eframe) only compiles
4	/// the pure-logic helpers (`parse_key_sequence`, `build_macro_config_from_form`)
5	/// exposed by the tests below.
6	
7	#[cfg(feature = "gui")]
8	pub use inner::*;
9	
10	#[cfg(feature = "gui")]
11	mod inner {
12	    use std::path::PathBuf;
13	
14	    use eframe::egui;
15	    use tracing;
16	
17	    use crate::config::MacroConfig;
18	    use crate::control::client::send_command;
19	    use crate::control::protocol::ControlRequest;
20	    use crate::pack::PackEditor;
21	
22	    use super::{build_macro_config_from_form, parse_key_sequence};
23	
24	    /// All mutable UI state for the pack editor panel.
25	    pub struct PackEditorState {
26	        pub editor: PackEditor,
27	        pub profile_dir: PathBuf,
28	        pub selected_category: Option<String>,
29	        pub selected_macro: Option<String>,
30	        /// Form input: macro name.
31	        pub form_name: String,
32	        /// Form input: trigger phrase.
33	        pub form_phrase: String,
34	        /// Form input: if_flag gate condition.
35	        pub form_if_flag: String,
36	        /// Form input: set_flag side effect.
37	        pub form_set_flag: String,
38	        /// Form input: comma-separated key sequence.
39	        pub form_keys: String,
40	        /// True while the category rename confirmation UI is visible.
41	        pub show_rename_warning: bool,
42	        /// Staging field for the new category name in Add Category toolbar.
43	        pub form_new_category: String,
44	        /// True after the first "Remove Macro" click — shows confirm button.
45	        pub pending_remove_macro: bool,
46	        /// Last synchronous error to surface inline in the panel.
47	        pub last_error: Option<String>,
48	    }
49	
50	    impl PackEditorState {
51	        pub fn new(editor: PackEditor, profile_dir: PathBuf) -> Self {
52	            Self {
53	                editor,
54	                profile_dir,
55	                selected_category: None,
56	                selected_macro: None,
57	                form_name: String::new(),
58	                form_phrase: String::new(),
59	                form_if_flag: String::new(),
60	                form_set_flag: String::new(),
61	                form_keys: String::new(),
62	                show_rename_warning: false,
63	                form_new_category: String::new(),
64	                pending_remove_macro: false,
65	                last_error: None,
66	            }
67	        }
68	
69	        /// Save the pack to disk then notify the daemon via SwitchProfile.
70	        ///
71	        /// Returns Ok if the disk write succeeded. Daemon notification failure is
72	        /// logged as a warning but does not make the overall save fail.
73	        pub fn save(&self) -> anyhow::Result<()> {
74	            let pack = self.editor.pack();
75	            pack.save_to_dir(&self.profile_dir)?;
76	
77	            let macro_count = pack.categories.iter().map(|c| c.macros.len()).sum::<usize>();
78	            let path = self.profile_dir.display().to_string();
79	            tracing::info!(path, macro_count, "pack saved");
80	
81	            let name = pack.name.clone();
82	            if let Err(e) = send_command(ControlRequest::SwitchProfile { name }) {
83	                let reason = e.to_string();
84	                tracing::warn!(reason, "SwitchProfile dispatch failed");
85	            }
86	
87	            Ok(())
88	        }
89	    }
