17	/// A tracing subscriber layer that forwards formatted log records to a channel.
18	struct ChannelLayer {
19	    tx: mpsc::SyncSender<String>,
20	}
21	
22	impl<S> tracing_subscriber::Layer<S> for ChannelLayer
23	where
24	    S: tracing::Subscriber,
25	{
26	    fn on_event(
27	        &self,
28	        event: &tracing::Event<'_>,
29	        _ctx: tracing_subscriber::layer::Context<'_, S>,
30	    ) {
31	        let mut visitor = MessageVisitor(String::new());
32	        event.record(&mut visitor);
33	        let line = format!("[{}] {}", event.metadata().level(), visitor.0);
34	        // Non-blocking send — drop if buffer full to avoid blocking the UI thread.
35	        let _ = self.tx.try_send(line);
36	    }
37	}
