452	fn handle_save(app: &mut VibeAttackConfigApp) {
453	    use vibe_attack::control::client::send_command;
454	    use vibe_attack::control::protocol::ControlRequest;
455	
456	    let Some(cached) = app.cached_config.as_ref() else {
457	        app.config.set_status("No config loaded — cannot save.");
458	        return;
459	    };
460	
461	    match save_app_to_config(&app.config, cached, None) {
462	        Err(e) => {
463	            app.config.set_status(format!("Save failed: {e}"));
464	            return;
465	        }
466	        Ok(updated) => {
467	            app.cached_config = Some(updated);
468	        }
469	    }
470	
471	    if !app.config.daemon_running {
472	        app.config
473	            .set_status("Saved to disk — daemon not running, runtime changes skipped.");
474	        return;
475	    }
476	
477	    // Dispatch four control commands; collect any failures.
478	    let commands = [
479	        ControlRequest::SetMode { mode: app.config.mode.clone() },
480	        ControlRequest::SetThreshold {
481	            threshold: app.config.threshold_pct as f32 / 100.0,
482	        },
483	        ControlRequest::SetInputDevice {
484	            device: app.config.input_device.clone(),
485	        },
486	        ControlRequest::SetPttBinding {
487	            key: app.config.ptt_binding.clone(),
488	        },
489	    ];
490	
491	    let mut errors: Vec<String> = Vec::new();
492	    for cmd in commands {
493	        let label = format!("{cmd:?}");
494	        if let Err(e) = send_command(cmd) {
495	            errors.push(format!("Failed to send {label}: {e}"));
496	        }
497	    }
498	
499	    if errors.is_empty() {
500	        app.config.set_status("Saved and applied.");
501	    } else {
502	        app.config.set_status(errors.join("; "));
503	    }
504	}
